import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"大水法","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/yuanmingyuan/dashuifa.md","filePath":"landmarks/yuanmingyuan/dashuifa.md","lastUpdated":1784720050000}'),n={name:"landmarks/yuanmingyuan/dashuifa.md"};function o(i,t,s,d,h,u){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="大水法" tabindex="-1">大水法 <a class="header-anchor" href="#大水法" aria-label="Permalink to &quot;大水法&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1684511846255-ab3f1c089f65?w=1200&amp;q=80" alt="大水法遗址"></p><blockquote><p>大理石巨柱依旧矗立，喷泉的水声却已沉寂百余年——这里是圆明园最震撼人心的废墟，也是一座民族记忆的纪念碑。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>大水法位于长春园北部的<a href="/beijing-travel-guide/landmarks/yuanmingyuan/xiyang-lou.html">西洋楼建筑群</a>中轴线南端，是整个西洋楼景区的主景，也是今日圆明园遗址最具标志性的景观。&quot;水法&quot;是清代对西方喷泉（fountain）的音义合译，&quot;大水法&quot;即&quot;大喷泉&quot;之意。</p><p>大水法建成于乾隆二十四年（1759年）前后，由意大利传教士、宫廷画师<strong>郎世宁</strong>设计，法国传教士<strong>蒋友仁</strong>负责水力机械监修。主体为一座巴洛克风格的石龛式建筑，前设椭圆形喷水池，池中布置铜鹿、铜狗等动物雕塑，引水激射，声如雷鸣，数里之外可闻，故又有&quot;猎狗逐鹿&quot;之景名。</p><p>1860年10月英法联军焚园之后，木构部分尽毁，唯有巨大的汉白玉构件与残柱历经风雨仍矗立不倒。1900年八国联军侵华期间，残存构件又遭进一步劫掠破坏。</p><p>今天游客所见的那片苍凉而庄严的石阵，正是大水法的遗存——它已成为圆明园的象征，出现在几乎所有关于圆明园的影像与画作之中。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>建成年代</strong></td><td style="text-align:left;">乾隆二十四年（1759年）前后</td></tr><tr><td style="text-align:left;"><strong>设计者</strong></td><td style="text-align:left;">郎世宁（意大利）设计，蒋友仁（法国）监修水力</td></tr><tr><td style="text-align:left;"><strong>建筑风格</strong></td><td style="text-align:left;">巴洛克式石构建筑，汉白玉雕饰</td></tr><tr><td style="text-align:left;"><strong>功能</strong></td><td style="text-align:left;">皇家欧式喷泉，&quot;猎狗逐鹿&quot;水法盛景</td></tr><tr><td style="text-align:left;"><strong>门票</strong></td><td style="text-align:left;">含在西洋楼遗址区15元门票内</td></tr><tr><td style="text-align:left;"><strong>现状</strong></td><td style="text-align:left;">仅存石龛残柱、喷水池基址、远瀛观石门</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><h3 id="石龛式主楼" tabindex="-1">石龛式主楼 <a class="header-anchor" href="#石龛式主楼" aria-label="Permalink to &quot;石龛式主楼&quot;">​</a></h3><p>大水法主体是一座高约十余米的石龛建筑，正面为巨大的券洞，券洞上方层层叠落巴洛克式石雕，饰以卷草、贝壳、涡卷纹样。券洞内原置石狮喷水装置，水自狮口激射而出，是整个喷泉群的核心水口。</p><p>石龛两侧对称布置汉白玉壁柱与雕花石屏，石料均取自北京房山，质地莹洁，虽经百年风化，雕纹依然清晰可辨。</p><h3 id="椭圆形喷水池-猎狗逐鹿" tabindex="-1">椭圆形喷水池：&quot;猎狗逐鹿&quot; <a class="header-anchor" href="#椭圆形喷水池-猎狗逐鹿" aria-label="Permalink to &quot;椭圆形喷水池：&quot;猎狗逐鹿&quot;&quot;">​</a></h3><p>主楼前为<strong>椭圆形大喷水池</strong>，长约30米。池中排列铜鹿、铜狗等十余尊动物雕塑：中央铜鹿昂首喷水，水柱高达数丈；周围十只铜狗逐鹿而吠，水自狗口激射，直注鹿身。</p><p>水激之声&quot;如万马奔腾&quot;，故称&quot;猎狗逐鹿&quot;。池岸以雕花石栏环绕，是当时中国最壮观的人工水景。</p><h3 id="远瀛观" tabindex="-1">远瀛观 <a class="header-anchor" href="#远瀛观" aria-label="Permalink to &quot;远瀛观&quot;">​</a></h3><p>大水法北侧的高台之上建有<strong>远瀛观</strong>，取&quot;远望瀛洲&quot;之意，是皇帝居高临下观赏大水法喷泉的观景建筑，也是西洋楼景区最宏丽的建筑之一。</p><p>远瀛观的汉白玉石屏风与台阶上精雕<strong>西洋军旗、甲胄、刀剑、火炮</strong>等纹样，是中西纹样交融的罕见实例。如今远瀛观仅余高大的石门与残基，仍可想见当年的恢宏气势。</p><h3 id="观水法" tabindex="-1">观水法 <a class="header-anchor" href="#观水法" aria-label="Permalink to &quot;观水法&quot;">​</a></h3><p>大水法正南设<strong>观水法</strong>，为皇帝观赏喷泉的宝座所在。此处坐南朝北，与水法主楼隔池相望：</p><ul><li>设石雕屏风五架，屏前置皇帝宝座</li><li>宝座视角正对大水法中轴线，喷泉全景一览无余</li><li>是西洋楼中轴线上&quot;观景—水景&quot;对位的精心设计</li></ul><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="郎世宁与蒋友仁的杰作" tabindex="-1">郎世宁与蒋友仁的杰作 <a class="header-anchor" href="#郎世宁与蒋友仁的杰作" aria-label="Permalink to &quot;郎世宁与蒋友仁的杰作&quot;">​</a></h3><p>乾隆帝对欧洲喷泉颇为好奇，命供职宫廷的意大利画师郎世宁主持设计。郎世宁精于绘画与透视，却不通水力，喷泉的供水难题最终由法国传教士蒋友仁解决——他用水车提水与重力供水相结合，将蓄水楼之水引至西洋楼各处。</p><p>大水法喷涌之日，乾隆龙颜大悦，此后常于观水法宝座上观赏水法，并多次命宫廷画师绘成图卷，留下了《大水法图》等宫廷绘画。</p><h3 id="残柱不倒的百年" tabindex="-1">残柱不倒的百年 <a class="header-anchor" href="#残柱不倒的百年" aria-label="Permalink to &quot;残柱不倒的百年&quot;">​</a></h3><p>1860年大火焚毁了西洋楼所有木构屋顶与装修，但汉白玉与大理石构件难以焚毁，大水法的巨型石柱、券洞与雕花石屏侥幸留存。此后百余年间，残石又屡遭盗凿搬运，幸而最核心的几组巨柱始终屹立于原址。</p><p>夕阳西下时分，残柱投下长长的影子，是圆明园最令人心绪难平的画面——这也是遗址公园&quot;保留残迹、不事重建&quot;保护理念的由来。</p><h3 id="铜版画中的盛景" tabindex="-1">铜版画中的盛景 <a class="header-anchor" href="#铜版画中的盛景" aria-label="Permalink to &quot;铜版画中的盛景&quot;">​</a></h3><p>乾隆年间宫廷制作的《圆明园西洋楼铜版图》中，有《大水法正面图》《远瀛观正面图》等幅，以欧洲透视法精确描绘了喷泉群的完整面貌。游览时对照遗址旁的铜版画展板，废墟与盛景叠映，时空仿佛在此交错。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>巨型大理石残柱</strong>：圆明园的标志性画面，清晨或黄昏光影最具感染力</li><li><strong>远瀛观石屏风</strong>：细看其上雕刻的西洋军旗甲胄纹样，中西合璧的实物见证</li><li><strong>椭圆形喷水池遗址</strong>：对照说明牌想象&quot;猎狗逐鹿&quot;喷泉当年的盛况</li><li><strong>观水法宝座遗址</strong>：从皇帝当年观水法的视角回望大水法，视角与百年前一致</li><li><strong>铜版画对照展板</strong>：园内展板有西洋楼铜版画原作，与残址一一对照</li><li><strong>房山汉白玉雕花残件</strong>：散落的卷草、贝壳纹石雕，巴洛克工艺近在眼前</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li>大水法位于<strong>西洋楼遗址区</strong>内，需在10元大门票之外另购15元遗址区门票</li><li>建议游览顺序：谐奇趣 → 海晏堂 → <strong>大水法</strong> → 远瀛观，沿西洋楼中轴线东行</li><li>遗址石构件为国家一级文物，<strong>严禁攀爬、触摸、刻画</strong></li><li>旺季游客众多，建议开园即入（7:00），可独享空旷的石阵</li><li>请保持肃穆：这里是国耻纪念地，不宜喧哗嬉闹</li><li>摄影爱好者推荐黄昏时分，残柱逆光剪影是圆明园最经典的影像</li></ul><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/">圆明园概览</a>——三园全貌与游览路线</li><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/haiyan-tang.html">海晏堂与十二生肖兽首</a>——大水法西侧的兽首喷泉</li><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/xiyang-lou.html">西洋楼建筑群</a>——大水法所属的西式景区</li><li><a href="/beijing-travel-guide/history/yuanmingyuan-ruins.html">圆明园遗址历史专题</a>——1860年焚毁始末</li></ul><hr><p><strong>📍 位置</strong>：长春园北部，西洋楼景区中轴线南端（海晏堂北侧、远瀛观南侧） <strong>⏱️ 建议游览</strong>：30-40分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/yuanmingyuan/">圆明园概览</a></p>',40)])])}const p=a(n,[["render",o]]);export{q as __pageData,p as default};
